proof_block:
// Scope the implication's antecedent with an `if`: inside the branch the
// per-index foralls and wf() conjuncts are unconditionally true, so the
// helper lemma's `requires` are met and the inline asserts go through.
// Outside the branch the postcondition is vacuously true.
if ((forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index] == 0)
    && post1_self_.wf()
    && (forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index] == 0)
    && post2_self_.wf())
{
    // Both ensures-foralls now hold; re-state them so z3 has trigger sites for
    // both runs in the same proof context.
    assert(forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index] == 0);
    assert(forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index] == 0);
    assert(post1_self_.wf());
    assert(post2_self_.wf());

    // Functional-uniqueness on the view: pointwise zero seqs of length N coincide.
    lemma_init2zero_view_unique::<N>(post1_self_, post2_self_);
    assert(post1_self_@ == post2_self_@);

    // Pointwise sequence equality + auto_ext_equal lifts to struct equality on Array.
    assert forall|index: int| 0 <= index < N implies post1_self_@[index] == post2_self_@[index] by {
        assert(post1_self_@[index] == 0);
        assert(post2_self_@[index] == 0);
    }
    assert(post1_self_ =~= post2_self_);
    assert(post1_self_ == post2_self_);

    // r1, r2 are both unit so trivially equal.
    assert(r1 == r2);
    assert(det_init2zero_equal(r1, r2, post1_self_, post2_self_));
}

helper_lemmas:
proof fn lemma_init2zero_view_unique<const N: usize>(
    post1: Array<usize, N>,
    post2: Array<usize, N>,
)
    requires
        post1.wf(),
        post2.wf(),
        forall|index: int| 0 <= index < N ==> #[trigger] post1@[index] == 0,
        forall|index: int| 0 <= index < N ==> #[trigger] post2@[index] == 0,
    ensures
        post1@ == post2@,
{
    assert forall|index: int| 0 <= index < N implies post1@[index] == post2@[index] by {
        assert(post1@[index] == 0);
        assert(post2@[index] == 0);
    }
    assert(post1@.len() == N);
    assert(post2@.len() == N);
    assert(post1@ =~= post2@);
}
